INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES
(gen_random_uuid(), 'is', 30, 1, NULL, 'Ulrich Zwingli em Is 30:1', 'Ulrich Zwingli interpreta este versículo a partir de a centralidade das Escrituras e da graça soberana. Em Isaías 30, Deus revela juízo, esperança e promessa messiânica de forma pastoral e transformadora, promovendo vida de oração. A verdade bíblica forma caráter, culto e missão. Aplicação: responda com oração, disciplina espiritual e serviço cristão.', 'Ulrich Zwingli', 'commentary', '#800080', NOW()),
(gen_random_uuid(), 'is', 31, 1, NULL, 'John Wesley em Is 31:1', 'John Wesley destaca o chamado ao arrependimento, fé viva e missão. Em Isaías 31, o foco recai sobre juízo, esperança e promessa messiânica e chama a igreja para santidade prática. O texto orienta a fé para uma obediência concreta e perseverante. Aplicação: receba esta verdade com fé, arrependimento e esperança ativa.', 'John Wesley', 'commentary', '#0E7490', NOW()),
(gen_random_uuid(), 'is', 32, 1, NULL, 'Adam Clarke em Is 32:1', 'Adam Clarke interpreta este versículo a partir de a exposição textual com aplicação pastoral objetiva. Em Isaías 32, Deus revela juízo, esperança e promessa messiânica de forma pastoral e transformadora, promovendo justiça com misericórdia. A verdade bíblica forma caráter, culto e missão. Aplicação: responda com oração, disciplina espiritual e serviço cristão.', 'Adam Clarke', 'commentary', '#B45309', NOW()),
(gen_random_uuid(), 'is', 33, 1, NULL, 'João Calvino em Is 33:1', 'Segundo João Calvino, a centralidade das Escrituras e da graça soberana ilumina o sentido deste texto. Isaías 33 mostra que juízo, esperança e promessa messiânica sustenta a caminhada da fé, especialmente em adoração reverente. A doutrina aqui conduz à devoção e à perseverança. Aplicação: firme-se nas promessas divinas e pratique a verdade com humildade.', 'João Calvino', 'commentary', '#800080', NOW()),
(gen_random_uuid(), 'is', 34, 1, NULL, 'John Brown of Haddington em Is 34:1', 'Na leitura de John Brown of Haddington, vemos a piedade prática e a santificação do coração. Isaías 34 evidencia juízo, esperança e promessa messiânica como eixo da vida do povo de Deus, com ênfase em amor fraternal. A passagem confronta o coração e organiza a prática diária do discípulo. Aplicação: submeta sua vontade à Palavra e caminhe em fidelidade.', 'John Brown of Haddington', 'commentary', '#2E8B57', NOW()),
(gen_random_uuid(), 'is', 35, 1, NULL, 'Albert Barnes em Is 35:1', 'Segundo Albert Barnes, a exposição textual com aplicação pastoral objetiva ilumina o sentido deste texto. Isaías 35 mostra que juízo, esperança e promessa messiânica sustenta a caminhada da fé, especialmente em arrependimento sincero. A doutrina aqui conduz à devoção e à perseverança. Aplicação: firme-se nas promessas divinas e pratique a verdade com humildade.', 'Albert Barnes', 'commentary', '#B45309', NOW()),
(gen_random_uuid(), 'is', 36, 1, NULL, 'Martinho Lutero em Is 36:1', 'Martinho Lutero destaca a centralidade das Escrituras e da graça soberana. Em Isaías 36, o foco recai sobre juízo, esperança e promessa messiânica e chama a igreja para vida de oração. O texto orienta a fé para uma obediência concreta e perseverante. Aplicação: receba esta verdade com fé, arrependimento e esperança ativa.', 'Martinho Lutero', 'commentary', '#800080', NOW()),
